        'spring:\n  messages:\n    fallbackToSystemLocale: false\n    basename: i18n/tips\n    encoding: UTF-8\n  flyway:\n    enabled: false\n  jmx:\n    enabled: false\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  servlet:\n    multipart:\n      max-file-size: 10MB\n      max-request-size: 30MB\n      file-size-threshold: 1\n  redis:\n    host: ${REDIS_HOST:localhost}\n    port: ${REDIS_PORT:6339}\n    password: ${REDIS_PWD:laiketui18}\n    lettuce:\n      pool:\n        # 连接池中的最大空闲连接 默认8\n        max-idle: 100\n        # 连接池中的最小空闲连接 默认0\n        min-idle: 0\n        # 连接池最大连接数 默认8 ，负数表示没有限制\n        max-active: 20\n        # 连接池最大阻塞等待时间（使用负值表示没有限制） 默认-1\n        max-wait: -1\n    timeout: 30000\n    database: ${REDIS_DB:0}\n  datasource:\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${DB_HOST:192.168.0.48}:${DB_PORT:3306}/${DB_NAME:v3_new_db}?useUnicode=true&autoReconnect=true&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n    username: ${DB_USER:root}\n    password: ${DB_PWD:root}\n    type: com.alibaba.druid.pool.DruidDataSource\n    initialSize: 1\n    minIdle: 1\n    maxIdle: 5\n    maxActive: 20\n    maxWait: 60000\n    timeBetweenEvictionRunsMillis: 60000\n    minEvictableIdleTimeMillis: 300000\n    validationQuery: SELECT 1 FROM DUAL\n    testWhileIdle: true\n    testOnBorrow: false\n    testOnReturn: false\n    poolPreparedStatements: true\n    filters: stat,wall\n    maxPoolPreparedStatementPerConnectionSize: 20\n    connectionProperties: druid.stat.mergeSql=true;druid.stat.slowSqlMillis=5000\n    druid:\n      stat-view-servlet:\n        enabled: true\n        url-pattern: /druid/*\n        reset-enable: true\n        login-username: admin\n        login-password: admin123\n        allow: 127.0.0.1\n\npush:\n  #是否开启 true开启 false 关闭 test\n  status: true\n  appid: nJaIsWP1Zt5g5XCapMDgs5\n  appkey: xgfKQIWvMo7Q0FqrKVMvr3\n  mastersecret: QSqJyNRI596TaL0AkbxIx1\n  host: http://sdk.open.api.igexin.com/apiex.htm\n  #收到消息是否立即启动应用：1为立即启动，2则广播等待客户端自启动\n  transmissiontype: 1\n\n\nuploadFile:\n  path: ${UPLOAD_PATH:/usr/local/imgs}\n\ndubbo:\n  reference:\n    generic: true\n\nelasticSearch:\n  hostlist: 47.107.123.240:19200\n  client:\n    connectNum: 10\n    connectPerRoute: 3\n\n\n',
