VALUES (381, 'laike-gateway-test.yml', 'DEFAULT_GROUP',
        'server:\n  port: 18001\n  tomcat:\n    uri-encoding: UTF-8\n  ssl:\n    enabled: false\n    connection-timeout: 20000\n\nspring:\n  main:\n    allow-bean-definition-overriding: true\n  jmx:\n    enabled: false\n  application:\n    name: laike-gateway\n  resources:\n    static-locations: classpath:/static/\n  mvc:\n    static-path-pattern: /gw/images/**\n  servlet:\n    multipart:\n      max-file-size: 10MB\n      max-request-size: 30MB\n      file-size-threshold: 1\n  multipart:\n    # 上传文件的临时目录\n    location: /upload\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  messages:\n    basenames: i18n/tips\n    encoding: UTF-8\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-gateway\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20888}\n\n',
        'f86a3dd251c802dcbd5f3fa8910c2998', '2023-03-28 10:13:51', '2024-01-26 01:46:27', NULL, '127.0.0.1', '',
        'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '网关模块', NULL, NULL, 'yaml', NULL, '');
