        '8248c58284c18efe38298d67a9d11aa8', '2024-01-15 07:37:33', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', '',
        'da8f7d37-960a-4c94-9691-9c77711d995c', 'java主线预售', NULL, NULL, 'yaml', NULL, '');
