VALUES (1458, 'laike-payment-prod.yml', 'DEFAULT_GROUP',
        'server:\n  port: 18001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /payment\n    \n#httpapi 节点id\nnode:\n  ip: 0.0.0.0\n\ndruid:\n  allow:\n    ip: 0.0.0.0\n  login:\n    user_name: root\n    password: laiketui\n\n#dubbo:\n#  application:\n#    name: laike-payment\n#  registry:\n#    id: zookeeper-registry\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: ${ZOOKEEPER_PORT:21896}\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#    monitor:\n#      protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-payment\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21896}\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-支付接口\n  desc: 来客电商订单接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.payment\n  groupName: 订单\n  contactName: payment\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n\nwechat:\n  payurl:\n    # APP下单API\n    app_wechat: https://api.mch.weixin.qq.com/v3/pay/transactions/app\n    # H5下单API\n    h5_wechat: https://api.mch.weixin.qq.com/v3/pay/transactions/jsapi\n    # JSAPI/小程序下单API\n    jsapi_mini_wechat: https://api.mch.weixin.qq.com/v3/pay/transactions/native\n    # Native下单API\n    native_wechat: https://api.mch.weixin.qq.com/v3/pay/transactions/h5\n  certurl:\n    # 服务器证书地址\n    certificatesUrl: https://api.mch.weixin.qq.com/v3/certificates\n  gzh:\n    redirect_uri: https://xiaochengxu.houjiemeishi.com/V3/\n',
        'f179478feb612dc4a889e403e628fcc3', '2024-01-25 09:17:13', '2024-01-26 01:39:13', 'nacos', '0:0:0:0:0:0:0:1',
        '', '23467031-bda4-48a0-a7ab-6bc1a4be22fd', '支付模块', '', '', 'yaml', '', '');
