VALUES (1461, 'laike-invoice-prod.yml', 'DEFAULT_GROUP',
        'server:\n  #配置成和tomcat端口一致（war部署）\n  port: 18001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /invoice\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 0.0.0.0\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-invoice\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21890}\n \n\n#swagger 配置\nswagger:\n  title: 来客电商-发票接口\n  desc: 来客电商发票接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.invoice\n  groupName: 发票\n  contactName: invoice\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n  ',
        'a38d0ea46192bc04f0b7269b7da9c814', '2024-01-25 09:17:13', '2024-01-25 09:44:56', 'nacos', '127.0.0.1', '',
        '23467031-bda4-48a0-a7ab-6bc1a4be22fd', '发票模块', '', '', 'yaml', '', '');
