VALUES (1464, 'laike-file-prod.yml', 'DEFAULT_GROUP',
        'server:\n  port: 18001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /file\n    \nnode:\n  ip: 0.0.0.0\n#dubbo:\n#  application:\n#    name: laike-file\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21892\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-file\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21892}\n\n#swagger 配置\nswagger:\n  title: 来客电商-资源上传\n  desc: 来客电商后台资源上传API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.file\n  groupName: 资源上传\n  contactName: file\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n',
        '4c8138ecd4b0b90d9f54d6e475619833', '2024-01-25 09:17:13', '2024-01-25 09:42:31', 'nacos', '127.0.0.1', '',
        '23467031-bda4-48a0-a7ab-6bc1a4be22fd', '资源模块', '', '', 'yaml', '', '');
