        '925acbf4b5506b21f2fa7a7565316607', '2024-01-25 09:17:13', '2024-01-25 09:39:23', 'nacos', '127.0.0.1', '',
        '23467031-bda4-48a0-a7ab-6bc1a4be22fd', 'im服务配置', '', '', 'yaml', '', '');
