        'server:\n  port: 18001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /sign\n\nnode:\n  ip: 0.0.0.0\n\n#dubbo:\n#  application:\n#    name: laike-presell\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21924\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-plugin-sign\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21924}\n  \n\n#swagger 配置\nswagger:\n  title: 来客电商-签到接口\n  desc: 来客电商签到接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.presell\n  groupName: 签到\n  contactName: sign\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com',
        'b58e098ef844e183734eccaddde932f6', '2024-01-26 01:43:10', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', '',
        'da8f7d37-960a-4c94-9691-9c77711d995c', 'java主线签到【目前无此插件】', NULL, NULL, 'yaml', NULL, '');
