CREATE TABLE `config_info_beta`
(
    `id`                 bigint(20)                    NOT NULL AUTO_INCREMENT COMMENT 'id',
    `data_id`            varchar(255) COLLATE utf8_bin NOT NULL COMMENT 'data_id',
