VALUES (1101, 84, 'laike-online-message-dev.yml', 'DEFAULT_GROUP', '',
        'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18180}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /message\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 127.0.0.1\n\n# Nacos 注册中心\n# dubbo:\n#   application:\n#     name: laike-user\n#     # 禁用QOS同一台机器可能会有端口冲突现象\n#     qos-enable: false\n#     qos-accept-foreign-ip: false\n#     # 配置注册中心\n#   registry:\n#     address: nacos://localhost:8848\n#   # 设置超时时间\n#   consumer:\n#     timeout: 6000\n#   protocol:\n#     name: dubbo\n#     port: ${NACOS_PORT:21889} \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-online-message\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21897} \n\n#swagger 配置\nswagger:\n  title: 来客电商-在线聊天\n  desc: 来客电商在线聊天接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.messages\n  groupName: 在线聊天\n  contactName: message\n  contactUrl: http://www.laiketui.com/\n  contactEmail:',
        '5b4fbd4df39860c04f8dbf85aaaa1dc9', '2024-01-15 15:41:14', '2024-01-15 07:41:14', 'nacos', '0:0:0:0:0:0:0:1',
        'U', 'da8f7d37-960a-4c94-9691-9c77711d995c', '');
