VALUES (129, 107, 'laike-user-local.yml', 'DEFAULT_GROUP', '',
        'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18002}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /user\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 127.0.0.1\n\nlogging:\n  config: classpath:logback-spring.xml\n  level:\n    com:\n      laiketui: debug\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-user\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21889}\n  reference:\n    generic: true\n#swagger 配置\nswagger:\n  title: 来客电商-用户接口\n  desc: 来客电商用户接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.user\n  groupName: 用户\n  contactName: user\n  contactUrl: http://www.laiketui.com/\n  contactEmail:',
        '9b880bb73a94d072270c93c78439a33e', '2024-01-15 16:31:12', '2024-01-15 08:31:13', 'nacos', '127.0.0.1', 'U',
        'f124b515-5b21-4bf8-9f72-25b585ee1343', '');
