        'server:\n  port: ${TOMCAT_PORT:18808}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /diy\n    \nnode:\n  ip: 127.0.0.1\n\n#dubbo:\n#  application:\n#    name: laike-diy\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 20904\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-diy\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20904}\n\n#swagger 配置\nswagger:\n  title: 来客电商-diy模板接口\n  desc: 来客电商diy模板接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.diy\n  groupName: diy模板\n  contactName: diy\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com\n',
        'e8c57aa145d682fc7db08cfdad6dcefa', '2024-01-15 17:02:35', '2024-01-15 09:02:36', 'nacos', '0:0:0:0:0:0:0:1',
        'U', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '');
