VALUES (1216, 247, 'laiketui-cloud-gateway-local.yml', 'DEFAULT_GROUP', '',
        'server:\n  port: 9526\n  servlet:\n    context-path: /scgw\n    \nspring:\n  cloud:\n    gateway:\n      # 处理跨域请求\n      globalcors:\n        add-to-simple-url-handler-mapping: true\n        cors-configurations:\n          \'[/**]\':\n            allowedHeaders: \"*\"\n            allowedOrigins: \"*\"\n            allowCredentials: true\n            allowedMethods:\n              - GET\n              - POST\n              - DELETE\n              - HEAD\n              - PUT\n              - OPTION \n      default-filters:\n            - DedupeResponseHeader=Vary Access-Control-Allow-Origin Access-Control-Allow-Credentials, RETAIN_FIRST\n\n      routes:\n        # 配置模块路由\n        # PC店铺端接口\n        - id: admin-mch\n          uri: lb://admin-mch\n          predicates:\n            - Path=/admin-mch/**\n#          filters:\n#            - StripPrefix=1\n        # 商城管理后台\n        - id: admin\n          uri: lb://admin\n          predicates:\n            - Path=/admin/**,/saas/**\n        #  filters:\n        #   - StripPrefix=1\n        # 供应商\n        - id: supplier\n          uri: lb://supplier\n          predicates:\n            - Path=/supplier/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端接口\n        - id: app\n          uri: lb://app\n          predicates:\n            - Path=/app/**\n#          filters:\n#            - StripPrefix=1\n        # 优惠券\n        - id: coupon\n          uri: lb://coupon\n          predicates:\n            - Path=/coupon/**\n#          filters:\n#            - StripPrefix=1\n        # 首页DIY\n        - id: diy\n          uri: lb://diy\n          predicates:\n            - Path=/diy/**\n#          filters:\n#            - StripPrefix=1\n        # 资源文件\n        - id: file\n          uri: lb://file\n          predicates:\n            - Path=/file/**\n#          filters:\n#            - StripPrefix=1\n        # 运费\n        - id: freight\n          uri: lb://freight\n          predicates:\n            - Path=/freight/**\n#          filters:\n#            - StripPrefix=1\n        # 网关\n        - id: gateway\n          uri: lb://gateway\n          predicates:\n            - Path=/gw/**\n        # 发票\n        - id: invoice\n          uri: lb://invoice\n          predicates:\n            - Path=/invoice/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端店铺接口\n        - id: mch\n          uri: lb://mch\n          predicates:\n            - Path=/mch/**\n#          filters:\n#            - StripPrefix=1\n        # 会员制\n        - id: member\n          uri: lb://member\n          predicates:\n            - Path=/member/**\n#          filters:\n#            - StripPrefix=1\n        # 订单\n        - id: order\n          uri: lb://order\n          predicates:\n            - Path=/order/**\n#          filters:\n#            - StripPrefix=1\n        # 支付\n        - id: payment\n          uri: lb://payment\n          predicates:\n            - Path=/payment/**\n#          filters:\n#            - StripPrefix=1\n        # 竞拍\n        - id: auction\n          uri: lb://auction\n          predicates:\n            - Path=/auction/**\n#          filters:\n#            - StripPrefix=1\n        # 分销\n        - id: distribute\n          uri: lb://distribute\n          predicates:\n            - Path=/distribute/**\n#          filters:\n#            - StripPrefix=1\n        # 拼团\n        - id: group\n          uri: lb://group\n          predicates:\n            - Path=/group/**\n#          filters:\n#            - StripPrefix=1\n        #\n        - id: integral\n          uri: lb://integral\n          predicates:\n            - Path=/integral/**\n#          filters:\n#            - StripPrefix=1\n        # 签到\n        - id: sign\n          uri: lb://sign\n          predicates:\n            - Path=/sign/**\n#          filters:\n#            - StripPrefix=1\n        # 预售\n        - id: presell\n          uri: lb://presell\n          predicates:\n            - Path=/presell/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端商品\n        - id: products\n          uri: lb://products\n          predicates:\n            - Path=/products/**\n#          filters:\n#            - StripPrefix=1\n        # 秒杀\n        - id: seckill\n          uri: lb://seckill\n          predicates:\n            - Path=/seckill/**\n#          filters:\n#            - StripPrefix=1\n        # PC商城\n        - id: mall\n          uri: lb://mall\n          predicates:\n            - Path=/mall/**\n#          filters:\n#            - StripPrefix=1\n        # 定时任务\n        - id: laike-task\n          uri: lb://laike-task\n          predicates:\n            - Path=/task/**\n#          filters:\n#            - StripPrefix=1\n        # 用户信息\n        - id: user\n          uri: lb://user\n          predicates:\n            - Path=/user/**\n          # filters:\n          #   - StripPrefix=1\n        # seata\n        - id: seata-demo\n          uri: lb://seata-demo\n          predicates:\n            - Path=/seata-demo/**\n          # filters:\n          #   - StripPrefix=1',
        '77da7bdd7f153c8c95d0ba422c5603c0', '2024-01-25 09:55:45', '2024-01-25 01:55:45', 'nacos', '127.0.0.1', 'U',
        'f124b515-5b21-4bf8-9f72-25b585ee1343', '');
