VALUES (0, 278, 'laike-user-prod.yml', 'DEFAULT_GROUP', '',
        'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18002}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /user\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 127.0.0.1\n\n# Nacos 注册中心\n# dubbo:\n#   application:\n#     name: laike-user\n#     # 禁用QOS同一台机器可能会有端口冲突现象\n#     qos-enable: false\n#     qos-accept-foreign-ip: false\n#     # 配置注册中心\n#   registry:\n#     address: nacos://localhost:8848\n#   # 设置超时时间\n#   consumer:\n#     timeout: 6000\n#   protocol:\n#     name: dubbo\n#     port: ${NACOS_PORT:21889} \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-user\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21889} \n\n#swagger 配置\nswagger:\n  title: 来客电商-用户接口\n  desc: 来客电商用户接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.user\n  groupName: 用户\n  contactName: user\n  contactUrl: http://www.laiketui.com/\n  contactEmail:',
        '0eaae5d62b06402c3a98e5c0d24bd1e5', '2024-01-25 17:17:12', '2024-01-25 09:17:13', NULL, '127.0.0.1', 'I',
        '23467031-bda4-48a0-a7ab-6bc1a4be22fd', '');
