VALUES (299, 380, 'laike-gateway-dev.yml', 'DEFAULT_GROUP', '',
        'server:\n  port: ${tomcat_port:18001}\n  tomcat:\n    uri-encoding: UTF-8\n  ssl:\n    enabled: false\n    connection-timeout: 20000\n\nspring:\n  main:\n    allow-bean-definition-overriding: true\n  jmx:\n    enabled: false\n  application:\n    name: laike-gateway\n  resources:\n    static-locations: classpath:/static/\n  mvc:\n    static-path-pattern: /gw/images/**\n  servlet:\n    multipart:\n      max-file-size: 10MB\n      max-request-size: 30MB\n      file-size-threshold: 1\n  multipart:\n    # 上传文件的临时目录\n    location: /upload\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  messages:\n    basenames: i18n/tips\n    encoding: UTF-8\n\n#zookeeper dubbo\n#dubbo:\n#  application:\n#    name: laike-gateway\n#  registry:\n#    id: zookeeper-registry\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 20888\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 2\n#    timeout: 3000\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-gateway\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20888}\n\n',
        '6fd115a51a2fb6d78b83c05d7fef8b15', '2024-01-26 09:43:10', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', 'U',
        'da8f7d37-960a-4c94-9691-9c77711d995c', '');
