VALUES (303, 382, 'laike-file-dev.yml', 'DEFAULT_GROUP', '',
        'server:\n  port: ${tomcat_port:18001}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /file\n    \nnode:\n  ip: 127.0.0.1\n#dubbo:\n#  application:\n#    name: laike-file\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21892\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-file\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21892}\n\n#swagger 配置\nswagger:\n  title: 来客电商-资源上传\n  desc: 来客电商后台资源上传API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.file\n  groupName: 资源上传\n  contactName: file\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n',
        '6898bae190b6d18f9d46611b9ce79674', '2024-01-26 09:43:10', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', 'U',
        'da8f7d37-960a-4c94-9691-9c77711d995c', '');
INSERT INTO `his_config_info` (`id`, `nid`, `data_id`, `group_id`, `app_name`, `content`, `md5`, `gmt_create`,
                               `gmt_modified`, `src_user`, `src_ip`, `op_type`, `tenant_id`, `encrypted_data_key`)
VALUES (0, 383, 'laiketui-cloud-gateway-dev.yml', 'DEFAULT_GROUP', '',
        'server:\n  port: 9526\n  servlet:\n    context-path: /scgw\n    \nspring:\n  cloud:\n    gateway:\n      # 处理跨域请求\n      globalcors:\n        add-to-simple-url-handler-mapping: true\n        cors-configurations:\n          \'[/**]\':\n            allowedHeaders: \"*\"\n            allowedOrigins: \"*\"\n            allowCredentials: true\n            allowedMethods:\n              - GET\n              - POST\n              - DELETE\n              - HEAD\n              - PUT\n              - OPTION \n      default-filters:\n            - DedupeResponseHeader=Vary Access-Control-Allow-Origin Access-Control-Allow-Credentials, RETAIN_FIRST\n\n      routes:\n        # 配置模块路由\n        # PC店铺端接口\n        - id: admin-mch\n          uri: lb://admin-mch\n          predicates:\n            - Path=/admin-mch/**\n#          filters:\n#            - StripPrefix=1\n        # 商城管理后台\n        - id: admin\n          uri: lb://admin\n          predicates:\n            - Path=/admin/**,/saas/**\n        #  filters:\n        #   - StripPrefix=1\n        # 供应商\n        - id: supplier\n          uri: lb://supplier\n          predicates:\n            - Path=/supplier/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端接口\n        - id: app\n          uri: lb://app\n          predicates:\n            - Path=/app/**\n#          filters:\n#            - StripPrefix=1\n        # 优惠券\n        - id: coupon\n          uri: lb://coupon\n          predicates:\n            - Path=/coupon/**\n#          filters:\n#            - StripPrefix=1\n        # 首页DIY\n        - id: diy\n          uri: lb://diy\n          predicates:\n            - Path=/diy/**\n#          filters:\n#            - StripPrefix=1\n        # 资源文件\n        - id: file\n          uri: lb://file\n          predicates:\n            - Path=/file/**\n#          filters:\n#            - StripPrefix=1\n        # 运费\n        - id: freight\n          uri: lb://freight\n          predicates:\n            - Path=/freight/**\n#          filters:\n#            - StripPrefix=1\n        # 网关\n        - id: gateway\n          uri: lb://gateway\n          predicates:\n            - Path=/gw/**\n        # 发票\n        - id: invoice\n          uri: lb://invoice\n          predicates:\n            - Path=/invoice/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端店铺接口\n        - id: mch\n          uri: lb://mch\n          predicates:\n            - Path=/mch/**\n#          filters:\n#            - StripPrefix=1\n        # 会员制\n        - id: member\n          uri: lb://member\n          predicates:\n            - Path=/member/**\n#          filters:\n#            - StripPrefix=1\n        # 订单\n        - id: order\n          uri: lb://order\n          predicates:\n            - Path=/order/**\n#          filters:\n#            - StripPrefix=1\n        # 支付\n        - id: payment\n          uri: lb://payment\n          predicates:\n            - Path=/payment/**\n#          filters:\n#            - StripPrefix=1\n        # 竞拍\n        - id: auction\n          uri: lb://auction\n          predicates:\n            - Path=/auction/**\n#          filters:\n#            - StripPrefix=1\n        # 分销\n        - id: distribute\n          uri: lb://distribute\n          predicates:\n            - Path=/distribute/**\n#          filters:\n#            - StripPrefix=1\n        # 拼团\n        - id: group\n          uri: lb://group\n          predicates:\n            - Path=/group/**\n#          filters:\n#            - StripPrefix=1\n        #\n        - id: integral\n          uri: lb://integral\n          predicates:\n            - Path=/integral/**\n#          filters:\n#            - StripPrefix=1\n        # 签到\n        - id: sign\n          uri: lb://sign\n          predicates:\n            - Path=/sign/**\n#          filters:\n#            - StripPrefix=1\n        # 预售\n        - id: presell\n          uri: lb://presell\n          predicates:\n            - Path=/presell/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端商品\n        - id: products\n          uri: lb://products\n          predicates:\n            - Path=/products/**\n#          filters:\n#            - StripPrefix=1\n        # 秒杀\n        - id: seckill\n          uri: lb://seckill\n          predicates:\n            - Path=/seckill/**\n#          filters:\n#            - StripPrefix=1\n        # PC商城\n        - id: mall\n          uri: lb://mall\n          predicates:\n            - Path=/mall/**\n#          filters:\n#            - StripPrefix=1\n        # 定时任务\n        - id: laike-task\n          uri: lb://laike-task\n          predicates:\n            - Path=/task/**\n#          filters:\n#            - StripPrefix=1\n        # 用户信息\n        - id: user\n          uri: lb://user\n          predicates:\n            - Path=/user/**\n          # filters:\n          #   - StripPrefix=1\n        # seata\n        - id: seata-demo\n          uri: lb://seata-demo\n          predicates:\n            - Path=/seata-demo/**\n          # filters:\n          #   - StripPrefix=1\n        - id: flashsale\n          uri: lb://flashsale\n          predicates:\n            - Path=/flashsale/**\n          # filters:\n          #   - StripPrefix=1',
        'ec1e93bd73f6fd4113f67a13f789797b', '2024-01-26 09:43:10', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', 'I',
        'da8f7d37-960a-4c94-9691-9c77711d995c', '');
INSERT INTO `his_config_info` (`id`, `nid`, `data_id`, `group_id`, `app_name`, `content`, `md5`, `gmt_create`,
                               `gmt_modified`, `src_user`, `src_ip`, `op_type`, `tenant_id`, `encrypted_data_key`)
VALUES (170, 384, 'comm-dev.yml', 'DEFAULT_GROUP', '',
        'spring:\n  cloud:\n    sentinel:\n      transport:\n        dashboard: 127.0.0.1:9527\n        port: 8719\n      eager: true\n  redis:\n    host: localhost\n    port: 6339\n    password: laiketui18\n    lettuce:\n      pool:\n        # 连接池中的最大空闲连接 默认8\n        max-idle: 100\n        # 连接池中的最小空闲连接 默认0\n        min-idle: 0\n        # 连接池最大连接数 默认8 ，负数表示没有限制\n        max-active: 20\n        # 连接池最大阻塞等待时间（使用负值表示没有限制） 默认-1\n        max-wait: -1\n    timeout: 30000\n    database: 10\n  # =======================shardingsphere 读写分离先搭建好主从库，再到这边配置 =============================\n  shardingsphere:\n    # 是否开启SQL显示\n    props:\n      sql:\n        show: true \n    datasource:\n      # names: lkt-ds-master-0,ds-slave-0-1\n      names: lkt-ds-master-0\n      #主库-写库 \n      # lkt-ds-master-0:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3307/java_main_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root\n      #主库-从库-读库 可多个从库 这里主从都是用的同一个库\n      # ds-slave-0-1:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3308/java_main_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root \n      #主库-写库\n      lkt-ds-master-0: \n        url: jdbc:mysql://192.168.0.48:3306/lkt_sc_v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        username: root\n        password: root\n        type: com.alibaba.druid.pool.DruidDataSource\n        driver-class-name: com.mysql.cj.jdbc.Driver \n        initial-size: 10\n        min-idle: 5\n        maxActive: 30\n        # 配置获取连接等待超时的时间\n        maxWait: 60000\n        # 配置间隔多久才进行一次检测，检测需要关闭的空闲连接，单位是毫秒\n        timeBetweenEvictionRunsMillis: 60000\n        # 配置一个连接在池中最小生存的时间，单位是毫秒\n        minEvictableIdleTimeMillis: 300000 \n        validationQuery: select 1\n        testWhileIdle: true\n        testOnBorrow: true\n        testOnReturn: false\n        # 打开PSCache，并且指定每个连接上PSCache的大小\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        # 配置监控统计拦截的filters，去掉后监控界面sql无法统计，\'wall\'用于防火墙\n        filters: stat,wall,slf4j\n        # 通过connectProperties属性来打开mergeSql功能；慢SQL记录\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=50000\n        wall:\n          multi-statement-allow: true\n      #主库-从库-读库 可多个从库 这里主从都是用的同一个库\n      # ds-slave-0-1:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3308/java_main_db?useUnicode=true&autoReconnect=true&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root \n      #   testWhileIdle: true\n    # 读写分离配置，需要的时候打开这个注释\n    #masterslave:\n    #  name: lkt-ms\n    #  load-balance-algorithm-type: round_robin\n    #  master-data-source-name: lkt-ds-master-0\n    #  slave-data-source-names: ds-slave-0-1\n\n  # datasource:\n  #   driver-class-name: com.mysql.cj.jdbc.Driver\n  #   #url: jdbc:mysql://${DB_HOST:192.168.0.48}:${DB_PORT:3306}/${DB_NAME:v3_new_db}?useUnicode=true&autoReconnect=true&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n  #   url: jdbc:mysql://${DB_HOST:192.168.0.48}:${DB_PORT:3306}/${DB_NAME:java_main_db}?useUnicode=true&autoReconnect=true&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n  #   username: ${DB_USER:root}\n  #   password: ${DB_PWD:root}\n  #   type: com.alibaba.druid.pool.DruidDataSource\n  #   initialSize: 1\n  #   minIdle: 1\n  #   maxIdle: 5\n  #   maxActive: 20\n  #   maxWait: 60000\n  #   timeBetweenEvictionRunsMillis: 60000\n  #   minEvictableIdleTimeMillis: 300000\n  #   validationQuery: SELECT 1 FROM DUAL\n  #   testWhileIdle: true\n  #   testOnBorrow: false\n  #   testOnReturn: false\n  #   poolPreparedStatements: true\n  #   filters: stat,wall\n  #   maxPoolPreparedStatementPerConnectionSize: 20\n  #   connectionProperties: druid.stat.mergeSql=true;druid.stat.slowSqlMillis=5000\n  #   druid:\n  #     stat-view-servlet:\n  #       enabled: true\n  #       url-pattern: /druid/*\n  #       reset-enable: true\n  #       login-username: admin\n  #       login-password: admin123\n  #       allow: 127.0.0.1\n\n  flyway:\n    enabled: false\n  jmx:\n    enabled: false\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  servlet:\n    multipart:\n      max-file-size: 10MB\n      max-request-size: 30MB\n      file-size-threshold: 1\n  messages:\n   fallbackToSystemLocale: false\n   basename: i18n/tips\n   encoding: UTF-8\n\n#文件上传路径\nuploadFile:\n  # path: ${UPLOAD_PATH:/Users/wangxian/imgs}\n  path: /usr/local/imgs/\n\n#日志级别\nlogging:\n  config: classpath:logback-spring.xml\n  level:\n    com:\n      laiketui: debug\n      \n##集群用\",\"连接\n# elasticSearch:\n#   hostlist: 47.107.123.240:19200\n#   client:\n#     connectNum: 10\n#     connectPerRoute: 3\n\n\n# # seata 配置\n# seata:\n#   # 使用哪个事务组\n#   tx-service-group: mygroup\n#   enabled: true\n#   service:\n#     # 事务组对应的集群民称  key是事务分组名称 value要和服务端的机房名称保持一致\n#     vgroup-mapping:\n#       mygroup: default   \n#     # seata-server的地址\n#     namespace: da8f7d37-960a-4c94-9691-9c77711d995c\n#     grouplist:\n#       seata-server: 47.107.123.240:8848 \n\n#   # 下面俩个seata服务的配置一样    \n#   registry:\n#     type: nacos\n#     nacos:\n#       application: seata-server\n#       serverAddr: 47.107.123.240:8848\n#       group: DEFAULT_GROUP\n#       cluster: default\n#       namespace: da8f7d37-960a-4c94-9691-9c77711d995c\n\nfeign:\n  hystrix:\n    enabled: false\n    \nribbon:\n  ReadTimeout: 10000\n  ConnectTimeout: 10000\n    \n# seata配置\nseata:\n  enabled: true\n  # Seata 应用编号，默认为 ${spring.application.name}\n  application-id: ${spring.application.name}\n  # Seata 事务组编号，用于 TC 集群名\n  tx-service-group: mygroup\n  # 关闭自动代理\n  # enable-auto-data-source-proxy: false\n  enableAutoDataSourceProxy: false\n  # use-jdk-proxy: true\n  # 服务配置项\n  service:\n    # 虚拟组和分组的映射\n    vgroup-mapping:\n      mygroup: default \n  # config:\n  #   type: nacos\n  #   nacos:\n  #     server-addr: 47.107.123.240:8848\n  #     namespace: da8f7d37-960a-4c94-9691-9c77711d995c\n  #     # 这是默认值\n  #     data-id: seataServer-dev.properties\n  #     # 这是默认值\n  #     group: DEFAULT_GROUP\n\n  # registry:\n  #   type: nacos\n  #   nacos:\n  #     server-addr: 47.107.123.240:8848\n  #     namespace: da8f7d37-960a-4c94-9691-9c77711d995c \n  #     #默认值和 config 的 SEATA_GROUP 不一样 \n  #     group: DEFAULT_GROUP \n\n\n',
        'c008e2989cdf2693310d943c186beb58', '2024-01-26 09:43:10', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', 'U',
        'da8f7d37-960a-4c94-9691-9c77711d995c', '');
INSERT INTO `his_config_info` (`id`, `nid`, `data_id`, `group_id`, `app_name`, `content`, `md5`, `gmt_create`,
                               `gmt_modified`, `src_user`, `src_ip`, `op_type`, `tenant_id`, `encrypted_data_key`)
VALUES (1103, 385, 'seataServer-dev.properties', 'DEFAULT_GROUP', '',
        '#For details about configuration items, see https://seata.io/zh-cn/docs/user/configurations.html\n#Transport configuration, for client and server\ntransport.type=TCP\ntransport.server=NIO\ntransport.heartbeat=true\ntransport.enableTmClientBatchSendRequest=false\ntransport.enableRmClientBatchSendRequest=true\ntransport.enableTcServerBatchSendResponse=false\ntransport.rpcRmRequestTimeout=30000\ntransport.rpcTmRequestTimeout=30000\ntransport.rpcTcRequestTimeout=30000\ntransport.threadFactory.bossThreadPrefix=NettyBoss\ntransport.threadFactory.workerThreadPrefix=NettyServerNIOWorker\ntransport.threadFactory.serverExecutorThreadPrefix=NettyServerBizHandler\ntransport.threadFactory.shareBossWorker=false\ntransport.threadFactory.clientSelectorThreadPrefix=NettyClientSelector\ntransport.threadFactory.clientSelectorThreadSize=1\ntransport.threadFactory.clientWorkerThreadPrefix=NettyClientWorkerThread\ntransport.threadFactory.bossThreadSize=1\ntransport.threadFactory.workerThreadSize=default\ntransport.shutdown.wait=3\ntransport.serialization=seata\ntransport.compressor=none\n\n#Transaction routing rules configuration, only for the client\n# 此处的mygroup名字可以自定义，只修改这个值即可\nservice.vgroupMapping.mygroup=default\n#If you use a registry, you can ignore it\n#service.default.grouplist=127.0.0.1:8091\n#service.enableDegrade=false\n#service.disableGlobalTransaction=false\n\n#Transaction rule configuration, only for the client\nclient.rm.asyncCommitBufferLimit=10000\nclient.rm.lock.retryInterval=10\nclient.rm.lock.retryTimes=30\nclient.rm.lock.retryPolicyBranchRollbackOnConflict=true\nclient.rm.reportRetryCount=5\nclient.rm.tableMetaCheckEnable=true\nclient.rm.tableMetaCheckerInterval=60000\nclient.rm.sqlParserType=druid\nclient.rm.reportSuccessEnable=false\nclient.rm.sagaBranchRegisterEnable=false\nclient.rm.sagaJsonParser=fastjson\nclient.rm.tccActionInterceptorOrder=-2147482648\nclient.tm.commitRetryCount=5\nclient.tm.rollbackRetryCount=5\nclient.tm.defaultGlobalTransactionTimeout=60000\nclient.tm.degradeCheck=false\nclient.tm.degradeCheckAllowTimes=10\nclient.tm.degradeCheckPeriod=2000\nclient.tm.interceptorOrder=-2147482648\nclient.undo.dataValidation=true\nclient.undo.logSerialization=jackson\nclient.undo.onlyCareUpdateColumns=true\nserver.undo.logSaveDays=7\nserver.undo.logDeletePeriod=86400000\nclient.undo.logTable=undo_log\nclient.undo.compress.enable=true\nclient.undo.compress.type=zip\nclient.undo.compress.threshold=64k\n#For TCC transaction mode\ntcc.fence.logTableName=tcc_fence_log\ntcc.fence.cleanPeriod=1h\n\n#Log rule configuration, for client and server\nlog.exceptionRate=100\n\n#Transaction storage configuration, only for the server. The file, db, and redis configuration values are optional.\n# 默认为file，一定要改为db，我们自己的服务启动会连接不到seata\nstore.mode=db\nstore.lock.mode=db\nstore.session.mode=db\n#Used for password encryption\n\n#These configurations are required if the `store mode` is `db`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `db`, you can remove the configuration block.\n# 修改mysql的配置\nstore.db.datasource=druid\nstore.db.dbType=mysql\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\n# 指定seata的数据库，下面会提\nstore.db.url=jdbc:mysql://192.168.0.48:3306/seata?useUnicode=true&rewriteBatchedStatements=true\nstore.db.user=root\nstore.db.password=root\nstore.db.minConn=5\nstore.db.maxConn=30\nstore.db.globalTable=global_table\nstore.db.branchTable=branch_table\nstore.db.distributedLockTable=distributed_lock\nstore.db.queryLimit=100\nstore.db.lockTable=lock_table\nstore.db.maxWait=50000\n\n\n#Transaction rule configuration, only for the server\nserver.recovery.committingRetryPeriod=600000\nserver.recovery.asynCommittingRetryPeriod=600000\nserver.recovery.rollbackingRetryPeriod=600000\nserver.recovery.timeoutRetryPeriod=600000\nserver.maxCommitRetryTimeout=-1\nserver.maxRollbackRetryTimeout=-1\nserver.rollbackRetryTimeoutUnlockEnable=false\nserver.distributedLockExpireTime=600000\nserver.xaerNotaRetryTimeout=600000\nserver.session.branchAsyncQueueSize=50000\nserver.session.enableBranchAsyncRemove=false\nserver.enableParallelRequestHandle=false\n\n#Metrics configuration, only for the server\nmetrics.enabled=false\nmetrics.registryType=compact\nmetrics.exporterList=prometheus\nmetrics.exporterPrometheusPort=9898\n',
        'd9bf9aabf967f6f7c5a3470147a51965', '2024-01-26 09:43:10', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', 'U',
        'da8f7d37-960a-4c94-9691-9c77711d995c', '');
