VALUES (370, 408, 'laike-invoice-demo.yml', 'DEFAULT_GROUP', '',
        'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18001}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /invoice\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 127.0.0.1\n#\n#dubbo:\n#  application:\n#    name: laike-invoice\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: ${ZOOKEEPER_PORT:21890}\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-invoice\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21890}\n \n\n#swagger 配置\nswagger:\n  title: 来客电商-发票接口\n  desc: 来客电商发票接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.invoice\n  groupName: 发票\n  contactName: invoice\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n  ',
        'e2961d06e3739d41fb957f61e0538e77', '2024-01-26 09:44:54', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', 'U',
