VALUES (204, 434, 'laike-task-test.yml', 'DEFAULT_GROUP', '',
        'server:\n  port: ${tomcat_port:18001}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /task\n    \n#dubbo:\n#  application:\n#    name: laike_app\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21898\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-task\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21898}\n\nlogging:\n  level:\n    com:\n      laiketui: info\n  config: classpath:logback.xml\n#swagger 配置\nswagger:\n  title: 来客电商-任务调度\n  desc: 来客电商任务调度\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.task\n  groupName: 任务调度\n  contactName: task\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n#xxl-job\nxxl:\n  job:\n    accessToken:\n    admin:\n      addresses: http://127.0.0.1:3366/task # 任务调度中心部署根地址（必填）\n    executor:\n      appname: laike-task                   # 对应 执行管理器 AppName\n      ip: 127.0.0.1                         # 执行器ip，可以不填，会自动识别注册\n      logpath: ./task.log                   # 执行器运行日志文件存储磁盘路径\n      logretentiondays: 30                  # 执行器日志保存天数，值大于3时生效，启用执行器log文件定期清理功能，否则不生效。\n      port: 2023                            # 执行器端口号 \n      #AccessToken：执行器通讯token，非空时启用',
        'babb96beaf74437b546073ec8d442596', '2024-01-26 09:46:27', '2024-01-26 01:46:27', NULL, '127.0.0.1', 'U',
        'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '');
