        'server:\n  port: 19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /member\n    \nnode:\n  ip: 0.0.0.0\n \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-plugin-member\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20906}\n\n#swagger 配置\nswagger:\n  title: 来客电商-会员制接口\n  desc: 来客电商会员制接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.member\n  groupName: 会员制\n  contactName: member\n  contactUrl: http://www.member.com/\n  contactEmail: 36309839@qq.com',
