VALUES (0, 460, 'laike-plugin-seckill-test.yml', 'DEFAULT_GROUP', '',
        'server:\n  port: 19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /seckill\n    \nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-seckill\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20904}\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-秒杀接口\n  desc: 来客电商秒杀接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.seckill\n  groupName: 秒杀\n  contactName: seckill\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com',
        '57c821c75b54923eb85c69595004dc20', '2024-01-26 09:46:27', '2024-01-26 01:46:27', NULL, '127.0.0.1', 'I',
        'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '');
